jQuery(function ($) {
  function getDeviceType() {
    if (window.innerWidth >= 1200) {
      return 'desktop';
    } else if (window.innerWidth >= 743) {
      return 'tablet';
    } else {
      return 'mobile';
    }
  }

  function initChangeTypeDeviceEvent() {
    let currentDevice = getDeviceType();

    function onWindowResizeHandler() {
      const nextDevice = getDeviceType();

      if (currentDevice !== nextDevice) {
        currentDevice = nextDevice;
        window.dispatchEvent(new CustomEvent('luxauto/deviceTypeChange', { detail: { type: nextDevice } }));
      }
    }

    window.addEventListener('resize', onWindowResizeHandler, { passive: true });
  }

  function initHomeCatalogCarousel() {
    const productCards = $('.products_stock__card');
    const productArrow = $('.products_stock__arrow');
    const productsStock = $('.products_stock__grid[data-slick="true"]');

    if (!productsStock.length) {
      return;
    }

    const slidesToShow = 3;
    const slidesToScroll = 2;

    /*
     * ===================================
     */

    /**
     * @param {number} total
     * @param {number} visible
     * @param {number} scrollable
     * @returns
     */
    function calcScrollWidth(total, visible, scrollable) {
      return (total - visible) / scrollable;
    }

    function onProductArrowsClickHandler() {
      switch (this.dataset?.type) {
        case 'prev':
          productsStock.slick('slickPrev');
          break;
        case 'next':
          productsStock.slick('slickNext');
          break;
      }
    }

    function onProductsCarouselChangeHandler(_, __, ___, nextSlide) {
      if (nextSlide === 0) {
        productArrow.filter('[data-type="prev"]').attr('disabled', '');
      } else {
        productArrow.filter('[data-type="prev"]').removeAttr('disabled');
      }

      if (nextSlide === productCards.length - slidesToShow) {
        productArrow.filter('[data-type="next"]').attr('disabled', '');
      } else {
        productArrow.filter('[data-type="next"]').removeAttr('disabled');
      }

      const step = nextSlide / slidesToScroll;
      const steps = calcScrollWidth(productCards.length, slidesToShow, slidesToScroll);

      $('.products_stock__scrollbar__line').css({ width: `${(100 / steps) * step}%` });
    }

    /*
     * ===================================
     */

    function initCarousel() {
      productsStock.slick({
        slidesToShow,
        slidesToScroll,
        dots: false,
        arrows: false,
        infinite: false,
        adaptiveHeight: false,
      });

      productArrow.on('click', onProductArrowsClickHandler);
      productsStock.on('beforeChange', onProductsCarouselChangeHandler);
    }

    if (getDeviceType() === 'desktop') {
      initCarousel();
    }

    window.addEventListener('luxauto/deviceTypeChange', ({ detail }) => {
      const deviceType = detail.type;

      if (deviceType === 'desktop') {
        initCarousel();
      } else {
        productArrow.off('click', onProductArrowsClickHandler);

        if (productsStock.hasClass('slick-initialized')) {
          productsStock.off('beforeChange', onProductsCarouselChangeHandler);
          productsStock.slick('unslick');
        }
      }
    });
  }

  /**
   * TODO: Добавить проверку на тип экрана при отключении кнопок
   */
  function initLeasingReviewsCarousel() {
    const section = document.querySelector('.customer_reviews');
    if (!section) return;

    const grid = section.querySelector('.customer_reviews__grid');
    const cards = section.querySelectorAll('.customer_reviews__card');
    const buttons = section.querySelectorAll('.customer_reviews__arrow__btn');

    if (grid.dataset?.slick === 'true') {
      const $grid = $(grid);
      const $cards = $(cards);
      const $buttons = $(buttons);
      const slidesToShow = 3;

      $grid.slick({
        slidesToShow,
        slidesToScroll: 1,
        dots: false,
        arrows: false,
        infinite: false,
        adaptiveHeight: false,
        responsive: [
          {
            breakpoint: 1200,
            settings: {
              slidesToShow: 2,
            },
          },
          {
            breakpoint: 743,
            settings: {
              slidesToShow: 1,
            },
          },
        ],
      });

      $grid.on('beforeChange', function (_, __, ___, nextSlide) {
        if (nextSlide === 0) {
          $buttons.filter('[data-type="prev"]').attr('disabled', '');
        } else {
          $buttons.filter('[data-type="prev"]').removeAttr('disabled');
        }

        if (nextSlide === $cards.length - slidesToShow) {
          $buttons.filter('[data-type="next"]').attr('disabled', '');
        } else {
          $buttons.filter('[data-type="next"]').removeAttr('disabled');
        }
      });

      $buttons.on('click', function () {
        switch (this.dataset?.type) {
          case 'prev':
            $grid.slick('slickPrev');
            break;
          case 'next':
            $grid.slick('slickNext');
            break;
        }
      });
    } else if (window.innerWidth >= 743) {
      const prevBtn = section.querySelector('.customer_reviews__arrow__btn[data-type="prev"]');
      const nextBtn = section.querySelector('.customer_reviews__arrow__btn[data-type="next"]');

      let current = 0;
      const showItems = 3;

      for (const button of buttons) {
        button.addEventListener('click', function () {
          switch (button.dataset?.type) {
            case 'prev':
              current--;
              break;
            case 'next':
              current++;
              break;
          }

          if (current === 0) {
            prevBtn.setAttribute('disabled', '');
          } else {
            prevBtn.removeAttribute('disabled');
          }

          if (current === grid.children.length - showItems) {
            nextBtn.setAttribute('disabled', '');
          } else {
            nextBtn.removeAttribute('disabled');
          }

          const cardWidth = Math.round(grid.offsetWidth / showItems);
          const gridGap = +getComputedStyle(grid).columnGap.replace('px', '');

          grid.scrollTo({ left: (cardWidth + gridGap) * current, behavior: 'smooth' });
        });
      }

      grid.scrollTo({ left: 0 });
    }
  }

  function emulateCursorProductPreviewsScrolling() {
    if (window.innerWidth < 1200) {
      return;
    }

    const carousel = document.querySelector('.product_summary__gallery__carousel');
    const previews = document.querySelectorAll('.product_summary__gallery__item');

    let isDragging = false;
    let startX;
    let scrollLeft;

    carousel.addEventListener('mousedown', (e) => {
      isDragging = true;
      startX = e.pageX - carousel.offsetLeft;
      scrollLeft = carousel.scrollLeft;
      carousel.style.cursor = 'grabbing';
    });

    carousel.addEventListener('mouseleave', () => {
      isDragging = false;
      carousel.style.cursor = 'grab';
    });

    carousel.addEventListener('mouseup', () => {
      isDragging = false;
      carousel.style.cursor = 'grab';
    });

    carousel.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      e.preventDefault();
      const x = e.pageX - carousel.offsetLeft;
      const walk = (x - startX) * 1.5; // Скорость прокрутки
      carousel.scrollTo({ left: scrollLeft - walk, behavior: 'smooth' });
    });

    for (const preview of previews) {
      preview.addEventListener('click', function () {
        if (!isDragging) {
          for (const preview of previews) {
            preview.setAttribute('data-active', 'false');
          }

          this.setAttribute('data-active', 'true');
        }
      });
    }
  }

  function toggleMobileHeaderWindow() {
    const html = document.querySelector('html');
    const window = document.querySelector('.header__window');
    const burger = document.querySelector('.header__above__burger');

    burger.addEventListener('click', () => {
      if (window.dataset?.visible === 'true') {
        html.style.removeProperty('overflow-y');
        window.setAttribute('data-visible', 'false');
      } else {
        window.setAttribute('data-visible', 'true');
        html.style.setProperty('overflow-y', 'hidden');
      }
    });
  }

  /*
   * ==============================
   */

  initChangeTypeDeviceEvent();

  /*
   * ==============================
   */

  initHomeCatalogCarousel();
  toggleMobileHeaderWindow();
  initLeasingReviewsCarousel();
  emulateCursorProductPreviewsScrolling();
});
